mapper.select:
select lend.id, lend.user_id, lend.book_id, lend.create_time as lend_time, lend.due_time, lend.return_time, lend.renew_count, lend.state, user.username, book.book_name from tb_lend lend join tb_user user on lend.user_id = user.id join tb_book book on lend.book_id = book.id where lend.is_delete = 0
and lend.user_id = #{lendPageDTO.userId}
and lend.book_id = #{lendPageDTO.bookId}
and lend.state = #{lendPageDTO.state}
